    pub(super) async fn create_monitoring_group(
        &self,
        config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        // Extract fields from config
        let display_name = config
            .optional_str("/identity/display_name")
            .map(String::from);
        let filter = config.optional_str("/config/filter").map(String::from);
        let is_cluster = config.optional_bool("/config/is_cluster");
        let name = config.require_str("/identity/name")?.to_string();
        let parent_name = config.optional_str("/config/parent_name").map(String::from);

        // Build SDK model
        let mut model = google_cloud_monitoring_v3::model::Group::default();
        if let Some(v) = display_name {
            model = model.set_display_name(v);
        }
        if let Some(v) = filter {
            model = model.set_filter(v);
        }
        if let Some(v) = is_cluster {
            model = model.set_is_cluster(v);
        }
        model = model.set_name(name.clone());
        if let Some(v) = parent_name {
            model = model.set_parent_name(v);
        }

        // Make API call
        let parent = format!("projects/{}", self.project_id);
        self.monitoring_groups()
            .await?
            .create_group()
            .set_name(&parent)
            .set_group(model)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("Create_group Group", e))?;

        let provider_id = format!("projects/{}/groups/{}", self.project_id, name);
        self.read_monitoring_group(&provider_id).await
    }

    pub(super) async fn read_monitoring_group(
        &self,
        provider_id: &str,
    ) -> Result<ResourceOutput, ProviderError> {
        let _name = provider_id
            .rsplit('/')
            .next()
            .unwrap_or(provider_id)
            .to_string();
        let group = self
            .monitoring_groups()
            .await?
            .get_group()
            .set_name(provider_id)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("GetGroup", e))?;

        let state = serde_json::json!({
            "identity": {
                "display_name": group.display_name.as_str(),
                "name": group.name.as_str(),
            },
            "config": {
                "filter": group.filter.as_str(),
                "is_cluster": group.is_cluster,
                "parent_name": group.parent_name.as_str(),
            },
        });

        let mut outputs = HashMap::new();
        outputs.insert("name".into(), serde_json::json!(&group.name));

        Ok(ResourceOutput {
            provider_id: provider_id.to_string(),
            state,
            outputs,
        })
    }

